""" This module contains functions that can be used to create
raster (image) of a PointCloud by projecting values from a point cloud's fields
onto an image.

There exist 3 "raterization function": ``PixelIsPoint``, ``PixelIsArea`` and
``PixelIsGlobal``

>>> RasterFunctionType.PixelIsPoint
<RasterFunctionType.PixelIsPoint: 0>
>>> RasterFunctionType.PixelIsArea
<RasterFunctionType.PixelIsArea: 1>
>>> RasterFunctionType.PixelIsGlobal
<RasterFunctionType.PixelIsGlobal: 2>

In the following schema, the different methods are illustrated in function of
the minimal point of the bounding box of the point cloud
(``bb_min = cloud.bb_min()``), and the bottom left pixel of the raster:

- For ``PixelIsPoint``, *bb_min* is represented by **P**: the coordinates of
  the bottom left corner of the raster is equal to *bb_min*.

- For ``PixelIsArea``, *bb_min* is represented by **A**: *bb_min* is centered
  on the bottom left pixel of the raster.

- For ``PixelIsGlobal``, *bb_min* is represented by **G**: the bottom
  left corner of the raster is aligned on a global grid calculated in function
  of the *precision* parameter. It garanties that rasters generated from multiple
  clouds with the same *precision* are aligned. They can therefore
  be merged without interpolation and data loss.

Schema::

    |       |
    |       |
    +-------+----
    | G     |
    |   A   |
    |       |
    P-------+----


These different methods are also illustrated in the picture above, where coordinates
are also shown. In black absolute coordinates relate to the world coordinate, and
different colors represent how the coordinate system changes from one method to
another. These coordinate conversion are handled with the
:class:`geosat.cloud.rasterization.Rasterizer` class which should be used to in
order to keep a GeoTransform and precision constantly over your processing workflow.
One should also note that the point located at absolute location (2; 2) is associated
with the pixel at coordinate (1; 1) and not the origin (0; 0). That is because when
using raster coordinate system we include the smaller boundary and exclude the bigger
boundary out of all raster locations covered by the corresponding pixel.


Since multiple point can be projected onto the same pixel,
a "value function" needs to be chosen to elect the pixel value.

There are 3 functions available:

>>> ValueFunctionType.Max
<ValueFunctionType.Max: 0>
>>> ValueFunctionType.Min
<ValueFunctionType.Min: 1>
>>> ValueFunctionType.Accumulate
<ValueFunctionType.Accumulate: 2>

 - Max means that the pixels will have the maximum values of the points.
 - Min means that the pixels will have the minimum values of the points.
 - Accumulate means that the pixels will contain the sum of values of the points
   (beware of possible overflows)
"""

import logging
from dataclasses import dataclass
from typing import (
    List,
    NamedTuple,
    Optional,
    Tuple,
    Union,
    TextIO,
    Any,
    Iterable,
)

import numpy as np
from geosat.tools.boundingboxes import BoundingBox
from typing_extensions import TypedDict, Self, deprecated

from geosat.cloud import PointCloud, cppraster
from geosat.cloud.cppraster import ValueFunctionType, RasterFunctionType
from geosat.cloud.exceptions import InvalidFieldName
from geosat.cloud.pointcloud import PathLike

logger = logging.getLogger(__name__)

_image_dtype_to_fn = {
    # Unsigned versions
    np.uint8: cppraster.uint8_raster,
    np.uint16: cppraster.uint16_raster,
    np.uint32: cppraster.uint32_raster,
    np.uint64: cppraster.uint64_raster,
    # Signed versions
    np.int8: cppraster.int8_raster,
    np.int16: cppraster.int16_raster,
    np.int32: cppraster.int32_raster,
    np.int64: cppraster.int64_raster,
    # Floating point versions
    np.float32: cppraster.f32_raster,
    np.float64: cppraster.f64_raster,
}

_image_dtype_to_apply_fn = {
    # Unsigned versions
    np.uint8: cppraster.uint8_apply_raster_values,
    np.uint16: cppraster.uint16_apply_raster_values,
    np.uint32: cppraster.uint32_apply_raster_values,
    np.uint64: cppraster.uint64_apply_raster_values,
    # Signed versions
    np.int8: cppraster.int8_apply_raster_values,
    np.int16: cppraster.int16_apply_raster_values,
    np.int32: cppraster.int32_apply_raster_values,
    np.int64: cppraster.int64_apply_raster_values,
    # Floating point versions
    np.float32: cppraster.f32_apply_raster_values,
    np.float64: cppraster.f64_apply_raster_values,
}


def create_raster(
    xs: np.ndarray,
    ys: np.ndarray,
    values: np.ndarray,
    precision: float,
    value_fn: ValueFunctionType,
    raster_fn: RasterFunctionType = RasterFunctionType.PixelIsPoint,
    init_value: Any = None,
    mask: Optional[np.ndarray] = None,
    shape: Optional[Tuple[int, int]] = None,
    origin: Optional[Tuple[float, float]] = None,
) -> np.ndarray:
    """Base function to create rasters.

    A raster is an image of shape (height, width).

    >>> from geosat.cloud import PointCloud, rasterization
    >>> cloud = PointCloud.read_from_path("tests/data/cloud.laz")
    >>> img = rasterization.create_raster(
    ...     cloud.x,
    ...     cloud.y,
    ...     cloud.intensity,
    ...     0.2,
    ...     ValueFunctionType.Max,
    ...     RasterFunctionType.PixelIsPoint,
    ...     init_value=0,
    ...     mask = cloud.classification== 2
    ... )
    >>> img.shape
    (10, 12)

    :param xs: x coordinates, maps the width of the raster
    :param ys: y coordinates, maps to the height of the raster
    :param values: values of points, that will result in values of pixels
    :param precision: size of each pixel, the bigger, the less precise
    :param value_fn: how to select between multiple values
        (see the module documentation)
    :param raster_fn: the rasterization function
        :class:`geosat.cloud.rasterization.RasterFunctionType`
    :param init_value: optional, value affected to all pixels before projecting points
        the function will try to use the best init_value
    :param mask: optional, array of bool, only points where the value is true
        will be projected onto the image
    :param shape: the desired shape ``(height, width)`` of the image. If not provided,
        it is deduced from ``xs`` and ``ys`` so that all the points are visible.
        If provided, points that fall outside the extent of the raster are not displayed.
    :param origin: the desired origin of the raster. If not provided, it is deduced from
        the minimum of ``xs`` and ``ys``. If provided, points that fall outside
        the raster extent are not displayed.

    :return: the image resulting of the rasterization process
    """
    try:
        return _image_dtype_to_fn[values.dtype.type](
            xs,
            ys,
            values,
            precision,
            raster_fn,
            value_fn,
            init_value=init_value,
            mask=mask,
            shape=shape,
            origin=origin,
        )
    except KeyError as exception:
        raise ValueError(f"dtype '{values.dtype}' not handled") from exception


def apply_raster_values(
    image: np.ndarray,
    xs: np.ndarray,
    ys: np.ndarray,
    values: np.ndarray,
    precision: float,
    raster_fn: RasterFunctionType = RasterFunctionType.PixelIsPoint,
    mask: Optional[np.ndarray] = None,
) -> None:
    """Reverse of :func:`geosat.cloud.rasterization.create_raster`.

    Takes the values of the pixels in the image and apply it the points' values.

    :param image: the raster to re-project on the point cloud
    :param xs: x coordinates, maps the width of the raster
    :param ys: y coordinates, maps to the height of the raster
    :param values: values that will be modified according to the pixels values
    :param precision: size of the pixels
    :param raster_fn: the rasterization function
        :class:`geosat.cloud.rasterization.RasterFunctionType`
    :param mask: optional, array of bool, only points where the value is true
        will be projected onto the image
    """
    if image.dtype != values.dtype:
        raise TypeError("Input image and values to be modified must have the same type")
    try:
        _image_dtype_to_apply_fn[values.dtype.type](
            image, xs, ys, values, precision, raster_fn, mask=mask
        )
    except KeyError as exception:
        raise ValueError(f"dtype '{values.dtype}' not handled") from exception


