def max_intensity_raster(
    cloud: PointCloud,
    precision: float,
    raster_fn: RasterFunctionType = RasterFunctionType.PixelIsPoint,
    mask: Optional[np.ndarray] = None,
) -> np.ndarray:
    """create a raster of the cloud where each pixel is the maximum intensity value
    of points corresponding to the pixel.

    Pixels where no points are projected have as value: 0

    :param cloud: The point cloud to rasterize
    :param precision: size of pixels
    :param raster_fn: the rasterization function
        :class:`geosat.cloud.rasterization.RasterFunctionType`
    :param mask: points to consider
    :return: the image as a numpy array of uint16
    """
    return create_raster(
        cloud.x,
        cloud.y,
        cloud.intensity,
        precision,
        ValueFunctionType.Max,
        raster_fn=raster_fn,
        mask=mask,
    )


def max_normalized_intensity_raster(
    cloud: PointCloud,
    precision: float,
    raster_fn: RasterFunctionType = RasterFunctionType.PixelIsPoint,
    mask: Optional[np.ndarray] = None,
) -> np.ndarray:
    """Create a raster of the cloud where each pixel is the maximum normalized
    intensity value of points corresponding to the pixel.

    - Normalized mean a value in the range [0.0, 1.0]
    - Pixels where no points are projected have as value: ``np.nan``
    - If all the intensisties are 0, the returned raster will contain 0.0
      where there is data

    :Example:

    >>> from geosat.cloud import PointCloud, rasterization
    >>> cloud_ = PointCloud.read_from_path("tests/data/cloud.laz")
    >>> img = rasterization.max_normalized_intensity_raster(
    ...     cloud_,
    ...     0.2,
    ... )
    >>> img.shape
    (10, 12)
    >>> img.dtype == float
    True
    >>> img = rasterization.max_normalized_intensity_raster(
    ...     PointCloud([[0., 0., 0.]],
    ...     fields={"intensity": np.array([0], dtype=np.uint16)}),
    ...     0.2,
    ... )
    >>> img.shape
    (1, 1)
    >>> float(img[0, 0])
    nan

    :param cloud: The point cloud to rasterize
    :param precision: size of pixels
    :param raster_fn: the rasterization function
        :class:`geosat.cloud.rasterization.RasterFunctionType`
    :param mask: points to consider
    :return: the image as a numpy array of double
    """
    normalized_intensities = (
        cloud.intensity / cloud.intensity.max() if cloud else np.empty(0)
    )
    return create_raster(
        cloud.x,
        cloud.y,
        normalized_intensities,
        precision,
        ValueFunctionType.Max,
        raster_fn=raster_fn,
        mask=mask,
    )


def min_normalized_intensity_raster(
    cloud: PointCloud,
    precision: float,
    raster_fn: RasterFunctionType = RasterFunctionType.PixelIsPoint,
    mask: Optional[np.ndarray] = None,
) -> np.ndarray:
    """Create a raster of the cloud where each pixel is the minimum normalized
    intensity value of points corresponding to the pixel.

    Normalized mean a value in the range [0.0, 1.0]
    Pixels where no points are projected have as value: ``np.nan``

    :param cloud: The point cloud to rasterize
    :param precision: size of pixels
    :param raster_fn: the rasterization function
        :class:`geosat.cloud.rasterization.RasterFunctionType`
    :param mask: points to consider
    :return: the image as a numpy array of double
    """
    normalized_intensities = (
        cloud.intensity / cloud.intensity.min() if cloud else np.empty(0)
    )
    return create_raster(
        cloud.x,
        cloud.y,
        normalized_intensities,
        precision,
        ValueFunctionType.Min,
        raster_fn=raster_fn,
        mask=mask,
    )


def mean_intensity_raster(
    cloud: PointCloud,
    precision: float,
    raster_fn: RasterFunctionType = RasterFunctionType.PixelIsPoint,
    mask: Optional[np.ndarray] = None,
) -> np.ndarray:
    """Create a raster of the cloud where each pixel has the mean
    of the intensities.

    Pixels where no points are projected have as value: 0

    :param cloud: The point cloud to rasterize
    :param precision: size of pixels
    :param raster_fn: the rasterization function
        :class:`geosat.cloud.rasterization.RasterFunctionType`
    :param mask: points to consider
    :return: the image as a numpy array
    """
    accumulation_img = create_raster(
        cloud.x,
        cloud.y,
        cloud.intensity.astype(np.uint64),
        precision,
        ValueFunctionType.Accumulate,
        raster_fn=raster_fn,
        mask=mask,
    )
    count_img = create_raster(
        cloud.x,
        cloud.y,
        np.ones(len(cloud), np.uint64),
        precision,
        ValueFunctionType.Accumulate,
        raster_fn=raster_fn,
        mask=mask,
    )
    count_img[count_img == 0] = 1  # Avoid dividing by 0
    return accumulation_img / count_img


def max_normalized_elevation_raster(
    cloud: PointCloud,
    precision: float,
    raster_fn: RasterFunctionType = RasterFunctionType.PixelIsPoint,
    mask: Optional[np.ndarray] = None,
) -> np.ndarray:
    """Create a raster of the cloud where each pixel is the maximum normalized z
     value of points corresponding to the pixel.

     Normalized mean a value in the range [0.0, 1.0]
     Pixels where no points are projected have as value: ``np.nan``

    :param cloud: The point cloud to rasterize
    :param precision: size of pixels
    :param raster_fn: the rasterization function
        :class:`geosat.cloud.rasterization.RasterFunctionType`
    :param mask: points to consider
    :return: the image as a numpy array of double
    """
    normalized_elevation = cloud.z / cloud.z.max() if cloud else np.empty(0)
    return create_raster(
        cloud.x,
        cloud.y,
        normalized_elevation,
        precision,
        ValueFunctionType.Max,
        raster_fn=raster_fn,
        mask=mask,
    )


