def max_rgb_raster(
    cloud: PointCloud,
    precision: float,
    raster_fn: RasterFunctionType = RasterFunctionType.PixelIsPoint,
    mask: Optional[np.ndarray] = None,
) -> np.ndarray:
    """Create a raster of the cloud where each pixel has 3 values
    and each of these values are the max of red, green, blue.

    Pixels where no points are projected have as value: 0

    :Example:

    >>> from geosat.cloud import PointCloud, rasterization
    >>> cloud_ = PointCloud.read_from_path("tests/data/cloud.laz")
    >>> img = rasterization.max_rgb_raster(
    ...     cloud_,
    ...     0.2,
    ...     RasterFunctionType.PixelIsArea
    ... )
    >>> img.shape
    (11, 12, 3)

    :param cloud: The point cloud to rasterize
    :param precision: size of pixels
    :param raster_fn: the rasterization function
        :class:`geosat.cloud.rasterization.RasterFunctionType`
    :param mask: points to consider
    :return: the image as a numpy array
    """
    r = max_red_raster(cloud, precision, raster_fn=raster_fn, mask=mask)
    g = max_green_raster(cloud, precision, raster_fn=raster_fn, mask=mask)
    b = max_blue_raster(cloud, precision, raster_fn=raster_fn, mask=mask)
    return np.stack((r, g, b), axis=2)


def classification_mask_raster(
    cloud: PointCloud,
    precision: float,
    classes: List[int],
    raster_fn: RasterFunctionType = RasterFunctionType.PixelIsPoint,
) -> np.ndarray:
    """Creates a binary mask raster

    Each pixel is either 0 or 255:
     - 255 if at least on point is classified one of the class in the input `classes`
       list
     - 0 otherwise

    :param cloud: the cloud to rasterize
    :param precision: the precision of the raster (pixel size)
    :param classes: list if classes to use to create the binary mask
    :param raster_fn: the rasterization function
        :class:`geosat.cloud.rasterization.RasterFunctionType` raster function
    :return: the corresponding ``np.array``
    """
    binary_classification = (
        np.isin(cloud.classification, classes).astype(np.uint8) * 255
    )
    return create_raster(
        cloud.x,
        cloud.y,
        binary_classification,
        precision,
        ValueFunctionType.Max,
        raster_fn=raster_fn,
    )


def classification_raster(
    cloud: PointCloud,
    precision: float,
    raster_fn: RasterFunctionType = RasterFunctionType.PixelIsPoint,
    mask: Optional[np.ndarray] = None,
) -> np.ndarray:
    return create_raster(
        cloud.x,
        cloud.y,
        cloud.classification,
        precision,
        ValueFunctionType.Max,
        raster_fn=raster_fn,
        mask=mask,
    )


def apply_classification_image(
    cloud: PointCloud,
    classification_img: np.ndarray,
    precision: float,
    raster_fn: RasterFunctionType = RasterFunctionType.PixelIsPoint,
    mask: Optional[np.ndarray] = None,
) -> None:
    apply_raster_values(
        classification_img,
        cloud.x,
        cloud.y,
        cloud.classification,
        precision,
        raster_fn,
        mask=mask,
    )


