def compute_raster_shape(
    bb_min: Iterable[float],
    bb_max: Iterable[float],
    precision: float,
    raster_fn: RasterFunctionType = RasterFunctionType.PixelIsPoint,
) -> Tuple[int, int]:
    """
    :param bb_min: minimum corner (west, south, bottom) of the bounding box
        of the cloud
    :param bb_max: maximum corner (east, north, top) of the bounding box
        of the cloud
    :param precision: the side length of the generated pixel, in the unit
        of the cloud
    :param raster_fn: the rasterization function
        :class:`geosat.cloud.rasterization.RasterFunctionType` raster function
    :return:

    >>> bb_min_ = (0., 0., 0.)
    >>> bb_max_ = (1.5, 1.5, 1.5)
    >>> precision_ = 1.0
    >>> compute_raster_shape(
    ...     bb_min_,
    ...     bb_max_,
    ...     precision_,
    ...     raster_fn=RasterFunctionType.PixelIsPoint
    ... )
    (2, 2)
    >>> compute_raster_shape(
    ...     bb_min_,
    ...     bb_max_,
    ...     precision_,
    ...     raster_fn=RasterFunctionType.PixelIsArea
    ... )
    (3, 3)
    >>> compute_raster_shape(
    ...     bb_min_,
    ...     bb_max_,
    ...     precision_,
    ...     raster_fn=RasterFunctionType.PixelIsGlobal
    ... )
    (2, 2)
    """
    xmin, ymin, *_ = bb_min
    xmax, ymax, *_ = bb_max
    raster_xmax = cppraster.compute_side_length(xmin, xmax, precision, raster_fn)
    raster_ymax = cppraster.compute_side_length(ymin, ymax, precision, raster_fn)
    return raster_ymax, raster_xmax


class InvalidShapeException(Exception):
    """An error raised when a raster shape does not match the theoretical shape"""


class InvalidCoordinatesException(Exception):
    """An error raised when trying to rasterize a cloud with coordinates
    outside the raster bounding box
    """


class InvalidPrecisionException(Exception):
    """An error raised when precision information does not match"""


class GeoDict(TypedDict, total=False):
    xmin: float
    xprecision: float
    xskew: float
    ymax: float
    yskew: float
    yprecision: float


class GeoTransform(NamedTuple):
    """The Geo transform is the information stored in a geotiff
    to be able to correctly map an image to an area in the world
    """

    xmin: float
    xprecision: float
    xskew: float
    ymax: float
    yskew: float
    yprecision: float

    @classmethod
    def from_cloud_bbox(
        cls,
        bb_min: Iterable[float],
        bb_max: Iterable[float],
        precision: float,
        raster_fn: RasterFunctionType = RasterFunctionType.PixelIsPoint,
    ) -> "GeoTransform":
        xmin, ymin, *_ = bb_min
        raster_xmin = cppraster.get_raster_minimum(precision, xmin, raster_fn)
        raster_ymin = cppraster.get_raster_minimum(precision, ymin, raster_fn)
        height, _width = compute_raster_shape(bb_min, bb_max, precision, raster_fn)
        return cls(
            xmin=raster_xmin,
            xprecision=precision,
            xskew=0.0,
            ymax=raster_ymin + (height * precision),
            yskew=0.0,
            yprecision=-precision,
        )

    @classmethod
    def from_point_cloud(
        cls,
        point_cloud: PointCloud,
        precision: float,
        raster_fn: RasterFunctionType = RasterFunctionType.PixelIsPoint,
    ) -> "GeoTransform":
        """
        :param point_cloud: The point cloud used to create the image
        :param precision: the precision used when creating the image
        :param raster_fn: the rasterization function
            :class:`geosat.cloud.rasterization.RasterFunctionType`
            used when creating the image
        :return: the corresponding ``GeoTransform``
        """
        return cls.from_cloud_bbox(
            point_cloud.bb_min(),
            point_cloud.bb_max(),
            precision,
            raster_fn=raster_fn,
        )

    @classmethod
    def from_point_cloud_and_raster(
        cls,
        point_cloud: PointCloud,
        raster: np.ndarray,
        precision: float,
        raster_fn: RasterFunctionType = RasterFunctionType.PixelIsPoint,
    ) -> "GeoTransform":
        """
        :param point_cloud: the point cloud used to create the image
        :param raster: the image
        :param precision: the precision used when creating the image
        :param raster_fn: the rasterization function
            :class:`geosat.cloud.rasterization.RasterFunctionType`
            used when creating the image
        :return: the corresponding ``GeoTransform``
        :raise InvalidShapeError: If the input raster shape first two dimensions do
            not match the theoretical shape computed from the point cloud.
        """
        bb_min = point_cloud.bb_min()
        bb_max = point_cloud.bb_max()
        shape = compute_raster_shape(bb_min, bb_max, precision, raster_fn=raster_fn)
        if shape != raster.shape[:2]:
            raise InvalidShapeException(
                f"The input raster with shape '{raster.shape}' does not match the "
                f"shape calculated from the point cloud bounding box '{shape}'. "
                f"Was the raster computed with a precision of {precision} and "
                f"the rasterization method {raster_fn}?"
            )
        return cls.from_cloud_bbox(bb_min, bb_max, precision, raster_fn=raster_fn)

    @classmethod
    def from_jgw(cls, path: PathLike) -> "GeoTransform":
        with open(path, "rt", encoding="utf-8") as world_file:
            return cls._from_textio(world_file)

    @classmethod
    def _from_textio(cls, world_file: TextIO) -> "GeoTransform":
        values = [float(line.strip()) for line in world_file.readlines()]
        xprecision, xskew, yskew, yprecision, xmin, ymax = values
        return cls(xmin, xprecision, xskew, ymax, yskew, yprecision)

    @classmethod
    def from_dict(cls, dict_: GeoDict) -> Self:
        return cls(
            dict_["xmin"],
            dict_["xprecision"],
            dict_["xskew"],
            dict_["ymax"],
            dict_["yskew"],
            dict_["yprecision"],
        )

    def to_dict(self) -> GeoDict:
        return GeoDict(
            xmin=self.xmin,
            xprecision=self.xprecision,
            xskew=self.xskew,
            ymax=self.ymax,
            yskew=self.yskew,
            yprecision=self.yprecision,
        )

    def get_file_content(self, world_file: TextIO) -> None:
        for field in (
            self.xprecision,
            self.xskew,
            self.yskew,
            self.yprecision,
            self.xmin,
            self.ymax,
        ):
            world_file.write(f"{field:.8f}\n")

    def write(self, path: PathLike) -> None:
        """
        Saves GeoTransformData as a file with 6 lines containing in this
        order : xprecision, xskew, yskew, yprecision, xmin, ymax

        To be moved in Rasterizer because geotransform values are not the same between
        world files and gdal geotransforms. See:
        https://gis.stackexchange.com/questions/133004/how-to-get-values-to-create-world-file-format

        :param path: file path to save geotransform.
        """
        with open(path, "wt", encoding="utf-8") as world_file:
            self.get_file_content(world_file)


class RasterizerDict(GeoDict):
    height: int
    width: int
    raster_fn: int


@dataclass(frozen=True)
class Rasterizer:
    """
    This class completes the GeoTransform class to have more information on
    global parameters used and keep its coherence.

    It considers that point clouds are already well aligned with xyz axis. Hence, all
    vertical elements should be aligned with the z axis. This Rasterizer class
    is used to create rasters from a top-down view only!

    It considers that absolute precision is the same between x and y axis.
    It also provides utility method to convert raster locations to absolute
    locations and vice-versa.

    :param geo_transform: `GeoTransform` instance to position our raster in the world
    :param shape: Number of pixels as tuple (height, width)
    :param raster_fn: a `RasterFunctionType` to know what pixel to assign to a
        certain world location.
    """

    geo_transform: GeoTransform
    shape: Tuple[int, int]
    raster_fn: RasterFunctionType = RasterFunctionType.PixelIsGlobal

    def __post_init__(self) -> None:
        if (
            self.geo_transform.xprecision <= 0.0
            or self.geo_transform.xprecision != -self.geo_transform.yprecision
        ):
            raise InvalidPrecisionException(
                f"Expected xprecision > 0 and yprecision == -xprecision. "
                f"Found xprecision={self.geo_transform.xprecision} and "
                f"yprecision={self.geo_transform.yprecision}"
            )
        if self.shape[0] <= 0 or self.shape[1] <= 0:
            raise InvalidShapeException(
                "Width and height of the underlying raster should be at least "
                f"1 pixel long. Found shape (height, width) = ({self.shape}))"
            )

    @property
    def precision(self) -> float:
        return self.geo_transform.xprecision

    @property
    def bb_min(self) -> Tuple[float, float]:
        """Returns the raster's bottom left absolute coordinates"""
        return (
            self.geo_transform.xmin,
            self.geo_transform.ymax - self.shape[0] * self.precision,
        )

    @property
    def bb_max(self) -> Tuple[float, float]:
        """Returns the raster's top right absolute coordinates"""
        return (
            self.geo_transform.xmin + self.shape[1] * self.precision,
            self.geo_transform.ymax,
        )

    @property
    def bounding_box(self) -> BoundingBox:
        xmin, ymin = self.bb_min
        xmax, ymax = self.bb_max
        return BoundingBox(xmin, ymin, xmax, ymax)

    @classmethod
    def from_cloud_bbox(
        cls,
        cloud_bb_min: Iterable[float],
        cloud_bb_max: Iterable[float],
        precision: float,
        raster_fn: RasterFunctionType = RasterFunctionType.PixelIsPoint,
    ) -> "Rasterizer":
        geo_transform = GeoTransform.from_cloud_bbox(
            cloud_bb_min, cloud_bb_max, precision, raster_fn=raster_fn
        )
        shape = compute_raster_shape(cloud_bb_min, cloud_bb_max, precision, raster_fn)
        return cls(geo_transform, shape, raster_fn)

    @classmethod
    def from_point_cloud(
        cls,
        point_cloud: PointCloud,
        precision: float,
        raster_fn: RasterFunctionType = RasterFunctionType.PixelIsPoint,
    ) -> "Rasterizer":
        """
        :param point_cloud: The point cloud used to create the image
        :param precision: the precision used when creating the image
        :param raster_fn: the rasterization function
            :class:`geosat.cloud.rasterization.RasterFunctionType`
            used when creating the image
        :return: the corresponding ``GeoTransform``
        """
        return cls.from_cloud_bbox(
            point_cloud.bb_min(), point_cloud.bb_max(), precision, raster_fn=raster_fn
        )

    @staticmethod
    @deprecated(
        "Use `create_rasterizer_from_gdal_dataset` from the `geotiff` module instead."
    )
    def from_gdal_dataset(
        *args: Any, **kwargs: Any
    ) -> Tuple["Rasterizer", Optional[np.ndarray]]:
        from .geotiff import create_rasterizer_from_gdal_dataset

        return create_rasterizer_from_gdal_dataset(*args, **kwargs)

    def to_relative(self, xy: np.ndarray, truncate: bool = True) -> np.ndarray:
        """Takes a 2D array with x coordinates in the first column and
        y in the second
        """
        coords = (xy[:, :2] - self.bb_min) / self.precision
        coords[:, 1] = (
            self.shape[0]
            - coords[:, 1]
            # shape[0] refers to the number of pixel on y axis as it is in the
            # numpy array system of coordinates
        )  # Invert y axis to match raster frame
        if truncate:
            return np.floor(coords).astype(np.int64)
        return coords

    def to_absolute(self, xy: np.ndarray) -> np.ndarray:
        x_abs = self.bb_min[0] + xy[:, 0].astype(np.float64) * self.precision
        y_abs = (
            self.bb_min[1]
            # shape[0] refers to the number of pixel on y axis as it is in the
            # numpy array system of coordinates
            + (float(self.shape[0]) - xy[:, 1].astype(np.float64)) * self.precision
        )
        return np.vstack((x_abs, y_abs)).T

    def rel_bb_to_absolute(self, bb: BoundingBox) -> BoundingBox:
        xys = np.array([[bb.xmin, bb.ymin], [bb.xmax, bb.ymax]])
        abs_xys = self.to_absolute(xys)
        xmin, ymin = np.min(abs_xys, axis=0)
        xmax, ymax = np.max(abs_xys, axis=0)
        return BoundingBox(xmin, ymin, xmax, ymax)

    def abs_bb_to_relative(self, bb: BoundingBox) -> BoundingBox:
        xys = np.array([[bb.xmin, bb.ymin], [bb.xmax, bb.ymax]])
        rel_xys = self.to_relative(xys)
        xmin, ymin = np.min(rel_xys, axis=0)
        xmax, ymax = np.max(rel_xys, axis=0)
        return BoundingBox(xmin, ymin, xmax, ymax)

    @classmethod
    def from_dict(cls, dict_: RasterizerDict) -> Self:
        gt = GeoTransform.from_dict(dict_)
        shape = dict_["height"], dict_["width"]
        rfn = RasterFunctionType(dict_["raster_fn"])
        return cls(gt, shape, rfn)

    def to_dict(self) -> RasterizerDict:
        geotransform_dict = self.geo_transform.to_dict()
        return RasterizerDict(
            xmin=geotransform_dict["xmin"],
            xprecision=geotransform_dict["xprecision"],
            xskew=geotransform_dict["xskew"],
            yskew=geotransform_dict["yskew"],
            yprecision=geotransform_dict["yprecision"],
            ymax=geotransform_dict["yprecision"],
            width=self.shape[1],
            height=self.shape[0],
            raster_fn=int(self.raster_fn),
        )

    def create_raster(
        self,
        cloud: PointCloud,
        on_fields: Union[str, List[str]],
        value_fn: ValueFunctionType,
        mask: Optional[np.ndarray] = None,
        init_value: Any = None,
    ) -> np.ndarray:
        """
        Creates a 2D array where values are induced by projecting point values
        to xy plan.

        :param cloud: the point cloud to rasterize
        :param on_fields: field to be used, if many are given then they will be stacked
        :param value_fn: value function to be used (Max, Min, or Accumulate)
        :param mask: points to be considered
        :param init_value: initial value for empty image
        :raise InvalidFieldName: if a field name in ``on_fields`` does not exist in
            the point cloud
        :return: ndarray with corresponding values
        """
        if isinstance(on_fields, list):
            rasters = [
                self.create_raster(cloud, field, value_fn, mask, init_value)
                for field in on_fields
            ]
            return np.stack(rasters, axis=2)

        if on_fields in cloud.fields:
            data = cloud.fields[on_fields]
        elif on_fields == "z":
            data = cloud.z
        else:
            raise InvalidFieldName(f"Invalid field: {on_fields}")

        return create_raster(
            cloud.x,
            cloud.y,
            data,
            self.precision,
            value_fn,
            raster_fn=self.raster_fn,
            mask=mask,
            init_value=init_value,
            shape=self.shape,
            origin=self.bb_min,
        )

    @deprecated(
        "Use `write_rasterizer_image_as_geotiff` from the `geotiff` module instead."
    )
    def write_image_as_geotiff(self, *args: Any, **kwargs: Any) -> None:
        from .geotiff import write_rasterizer_image_as_geotiff

        write_rasterizer_image_as_geotiff(self, *args, **kwargs)

    def __str__(self) -> str:
        return (
            f"{self.bb_min[0]}_{self.bb_max[1]}_{self.shape[0]}_"
            f"{self.shape[1]}_{self.precision}_{int(self.raster_fn)}"
        )

    def __repr__(self) -> str:
        return (
            f"{self.__class__.__name__}({repr(self.geo_transform)}, "
            f"{repr(self.shape)}, {self.raster_fn})"
        )


